fn next_permutation(arr: &mut [u8]) -> bool {
    if arr.len() <= 1 {
        return false;
    }
    let mut i = arr.len() - 1;
    while i > 0 && arr[i-1] >= arr[i] {
        i -= 1;
    }
    if i == 0 {
        return false;
    }
    let pivot_index = i - 1;
    let pivot = arr[pivot_index];
    let mut j = arr.len() - 1;
    while arr[j] <= pivot {
        j -= 1;
    }
    arr.swap(pivot_index, j);
    arr[i..].reverse();
    true
}

