fn next_permutation<T: Ord>(arr: &mut [T]) -> bool {
    if arr.len() <= 1 {
        return false;
    }
    let i = match (0..arr.len()-1).rev().find(|&i| arr[i] < arr[i+1]) {
        Some(i) => i,
        None => return false,
    };
    let j = (i+1..arr.len()).rposition(|j| arr[j] > arr[i]).unwrap();
    arr.swap(i, j);
    arr[i+1..].reverse();
    true
}

fn distinct_permutations(items: &[u32]) -> Vec<Vec<u32>> {
    let mut data = items.to_vec();
    data.sort();
    let mut permutations = Vec::new();
    permutations.push(data.clone());
    while next_permutation(&mut data) {
        permutations.push(data.clone());
    }
    permutations
}

