        if count[d] < required {
            continue;
        }
        let ch = std::char::from_digit(d as u32, 10).unwrap();
        current.push(ch);
        count[d] -= required;

        let res = generate_candidate_dfs(pos + 1, current, count, n_str, total_length, is_odd);

        count[d] += required;
        current.pop();

        if res.is_some() {
            return res;
        }
    }
